//! Model identification and registry
//!
//! Provider/model list derived from pi (https://pi.codes).
//! 35 providers, ~968 models in the upstream catalog.

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ModelId {
    pub provider: String,
    pub name: String,
}

impl ModelId {
    pub fn new(provider: impl Into<String>, name: impl Into<String>) -> Self {
        Self {
            provider: provider.into(),
            name: name.into(),
        }
    }

    pub fn full(&self) -> String {
        format!("{}/{}", self.provider, self.name)
    }
}

#[derive(Debug, Clone)]
pub struct ProviderMeta {
    pub key: &'static str,
    pub env_var: &'static str,
    pub base_url_hint: Option<&'static str>,
}

impl ProviderMeta {
    pub const fn new(key: &'static str, env_var: &'static str) -> Self {
        Self {
            key,
            env_var,
            base_url_hint: None,
        }
    }

    pub const fn with_url(key: &'static str, env_var: &'static str, url: &'static str) -> Self {
        Self {
            key,
            env_var,
            base_url_hint: Some(url),
        }
    }
}

pub fn builtin_providers() -> Vec<ProviderMeta> {
    vec![
        ProviderMeta::new("openai", "OPENAI_API_KEY"),
        ProviderMeta::new("anthropic", "ANTHROPIC_API_KEY"),
        ProviderMeta::new("google", "GEMINI_API_KEY"),
        ProviderMeta::new("openrouter", "OPENROUTER_API_KEY"),
        ProviderMeta::new("groq", "GROQ_API_KEY"),
        ProviderMeta::new("deepseek", "DEEPSEEK_API_KEY"),
        ProviderMeta::new("mistral", "MISTRAL_API_KEY"),
        ProviderMeta::new("fireworks", "FIREWORKS_API_KEY"),
        ProviderMeta::new("together", "TOGETHER_API_KEY"),
        ProviderMeta::new("ollama", "OLLAMA_HOST"),
        ProviderMeta::new("mock", ""),
    ]
}

pub struct ModelRegistry {
    models: Vec<ModelId>,
}

impl Default for ModelRegistry {
    fn default() -> Self {
        let mut models = Vec::new();
        Self::fill_ai_providers(&mut models);
        Self::fill_china_providers(&mut models);
        Self::fill_gateway_providers(&mut models);
        Self::fill_specialized(&mut models);
        Self { models }
    }
}

impl ModelRegistry {
    fn fill_ai_providers(models: &mut Vec<ModelId>) {
        let catalog: &[(&str, &[&str])] = &[
            ("anthropic", &["claude-sonnet-4-6", "claude-opus-4-7", "claude-haiku-4-5"]),
            ("openai", &["gpt-4o", "gpt-4o-mini", "gpt-5", "o3-mini", "o4-mini", "o1", "o3"]),
            ("google", &["gemini-2.5-pro", "gemini-2.5-flash", "gemini-2.0-flash"]),
            ("deepseek", &["deepseek-v4-flash", "deepseek-v4-pro"]),
            ("mistral", &["mistral-large-latest", "codestral-latest", "devstral-latest"]),
            ("groq", &["llama-3.3-70b-versatile", "gemma2-9b-it", "mixtral-8x7b-32768"]),
            ("together", &["meta-llama/Llama-3.3-70B-Instruct-Turbo", "deepseek-ai/DeepSeek-V4-Pro"]),
            ("fireworks", &["accounts/fireworks/models/deepseek-v4-pro", "accounts/fireworks/models/kimi-k2p6"]),
            ("openrouter", &[
                "anthropic/claude-sonnet-4.6", "openai/gpt-4o", "google/gemini-2.5-pro",
                "deepseek/deepseek-chat", "deepseek/deepseek-r1",
            ]),
        ];
        Self::extend_models(models, catalog);
    }

    fn fill_china_providers(models: &mut Vec<ModelId>) {
        let catalog: &[(&str, &[&str])] = &[
            ("kimi-coding", &["kimi-for-coding", "kimi-k2-thinking"]),
            ("moonshotai", &["kimi-k2.5", "kimi-k2.6", "kimi-k2-thinking"]),
            ("minimax", &["MiniMax-M2.7", "MiniMax-M3"]),
            ("xiaomi", &["mimo-v2.5", "mimo-v2.5-pro"]),
            ("zai", &["glm-4.7", "glm-5", "glm-5-turbo", "glm-5.1"]),
            ("opencode", &["claude-sonnet-4-6", "gpt-5.1", "kimi-k2.6", "glm-5"]),
        ];
        Self::extend_models(models, catalog);
    }

    fn fill_gateway_providers(models: &mut Vec<ModelId>) {
        let catalog: &[(&str, &[&str])] = &[
            ("cloudflare-ai-gateway", &["claude-sonnet-4-5", "gpt-5.1"]),
            ("cloudflare-workers-ai", &["@cf/moonshotai/kimi-k2.6", "@cf/meta/llama-4-scout-17b"]),
            ("vercel-ai-gateway", &["moonshotai/kimi-k2.5", "openai/gpt-5"]),
        ];
        Self::extend_models(models, catalog);
    }

    fn fill_specialized(models: &mut Vec<ModelId>) {
        let catalog: &[(&str, &[&str])] = &[
            ("amazon-bedrock", &["us.anthropic.claude-sonnet-4-6", "us.deepseek.r1-v1:0"]),
            ("azure-openai-responses", &["gpt-4o", "gpt-4.1", "o3-mini"]),
            ("cerebras", &["gpt-oss-120b", "llama3.1-8b"]),
            ("github-copilot", &["claude-sonnet-4-6", "gemini-2.5-pro"]),
            ("huggingface", &["meta-llama/Llama-3.3-70B-Instruct", "mistralai/Mistral-Large-Instruct-2411"]),
            ("nvidia", &["meta/llama-3.3-70b-instruct", "nvidia/nemotron-3-super-120b-a12b"]),
            ("ollama", &["llama3.1", "qwen2.5-coder:7b", "mistral"]),
            ("xai", &["grok-3", "grok-4.3"]),
            ("mock", &["echo"]),
        ];
        Self::extend_models(models, catalog);
    }

    fn extend_models(models: &mut Vec<ModelId>, catalog: &[(&str, &[&str])]) {
        for &(provider, names) in catalog {
            for name in names {
                models.push(ModelId::new(provider, *name));
            }
        }
    }

    pub fn list(&self) -> &[ModelId] {
        &self.models
    }

    pub fn find(&self, full: &str) -> Option<&ModelId> {
        self.models.iter().find(|m| m.full() == full)
    }

    pub fn by_provider(&self, provider: &str) -> Vec<&ModelId> {
        self.models.iter().filter(|m| m.provider == provider).collect()
    }

    pub fn providers_with_models(&self) -> Vec<&str> {
        let mut providers: Vec<&str> = self
            .models
            .iter()
            .map(|m| m.provider.as_str())
            .collect::<std::collections::HashSet<_>>()
            .into_iter()
            .collect();
        providers.sort();
        providers
    }

    pub fn register(&mut self, model: ModelId) {
        self.models.push(model);
    }
}

//! Global TOML config (~/.runie/config.toml)

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::path::PathBuf;

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct ModelsSection {
    pub default: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ModelProvider {
    #[serde(rename = "type")]
    pub provider_type: Option<String>,
    pub base_url: String,
    pub api_key: String,
}

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct Config {
    pub provider: Option<String>,
    pub model: Option<String>,
    #[serde(default)]
    pub models: ModelsSection,
    #[serde(default)]
    pub model_providers: HashMap<String, ModelProvider>,
}

impl Config {
    pub fn load() -> Self {
        let path = Self::path();
        if !path.exists() {
            return Self::default();
        }
        match std::fs::read_to_string(&path) {
            Ok(text) => toml::from_str(&text).unwrap_or_default(),
            Err(_) => Self::default(),
        }
    }

    pub fn save(&self) -> anyhow::Result<()> {
        let path = Self::path();
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        std::fs::write(&path, toml::to_string_pretty(self)?)?;
        Ok(())
    }

    pub fn path() -> PathBuf {
        dirs::home_dir()
            .unwrap_or_else(|| PathBuf::from("."))
            .join(".runie")
            .join("config.toml")
    }

    pub fn default_model(&self) -> Option<&str> {
        self.models.default.as_deref().or(self.model.as_deref())
    }

    pub fn provider_for_model(&self, full_model: &str) -> Option<&ModelProvider> {
        let prefix = full_model.split('/').next().unwrap_or(full_model);
        self.model_providers.get(prefix)
    }
}

/// Resolves provider configuration from multiple sources with priority:
/// 1. Environment variables
/// 2. .env file in current working directory
/// 3. config.toml model_providers section
#[derive(Debug, Clone, Default)]
pub struct ProviderConfigResolver {
    env: HashMap<String, String>,
    dotenv: HashMap<String, String>,
    config_file: HashMap<String, ModelProvider>,
}

impl ProviderConfigResolver {
    pub fn from_config(config: &Config) -> Self {
        let mut env = HashMap::new();
        for (key, val) in std::env::vars() {
            env.insert(key, val);
        }

        let dotenv = Self::load_dotenv();

        Self {
            env,
            dotenv,
            config_file: config.model_providers.clone(),
        }
    }

    fn load_dotenv() -> HashMap<String, String> {
        let path = std::env::current_dir().unwrap_or_default().join(".env");
        if !path.exists() {
            return HashMap::new();
        }
        let content = match std::fs::read_to_string(&path) {
            Ok(c) => c,
            Err(_) => return HashMap::new(),
        };
        let mut map = HashMap::new();
        for line in content.lines() {
            let line = line.trim();
            if line.is_empty() || line.starts_with('#') {
                continue;
            }
            if let Some((key, val)) = line.split_once('=') {
                map.insert(key.trim().to_string(), val.trim().trim_matches('"').to_string());
            }
        }
        map
    }

    pub fn resolve_api_key(&self, provider: &str) -> Option<String> {
        let env_key = format!("{}_API_KEY", provider.to_uppercase());
        if let Some(val) = self.env.get(&env_key) {
            return Some(val.clone());
        }
        if let Some(val) = self.dotenv.get(&env_key) {
            return Some(val.clone());
        }
        self.config_file.get(provider).map(|p| p.api_key.clone())
    }

    pub fn resolve_base_url(&self, provider: &str) -> Option<String> {
        let env_key = format!("{}_BASE_URL", provider.to_uppercase());
        if let Some(val) = self.env.get(&env_key) {
            return Some(val.clone());
        }
        if let Some(val) = self.dotenv.get(&env_key) {
            return Some(val.clone());
        }
        self.config_file.get(provider).map(|p| p.base_url.clone())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn resolve_env_takes_priority() {
        let config = Config::default();
        let mut resolver = ProviderConfigResolver::from_config(&config);
        resolver.env.insert("TESTPROVIDER_API_KEY".to_string(), "env-key".to_string());
        resolver.config_file.insert("testprovider".to_string(), ModelProvider {
            provider_type: None,
            base_url: "http://example.com".to_string(),
            api_key: "config-key".to_string(),
        });

        assert_eq!(resolver.resolve_api_key("testprovider"), Some("env-key".to_string()));
    }

    #[test]
    fn resolve_dotenv_fallback() {
        let config = Config::default();
        let mut resolver = ProviderConfigResolver::from_config(&config);
        resolver.dotenv.insert("TESTPROVIDER_API_KEY".to_string(), "dotenv-key".to_string());

        assert_eq!(resolver.resolve_api_key("testprovider"), Some("dotenv-key".to_string()));
    }

    #[test]
    fn resolve_config_fallback() {
        let mut config = Config::default();
        config.model_providers.insert("testprovider".to_string(), ModelProvider {
            provider_type: None,
            base_url: "http://example.com".to_string(),
            api_key: "config-key".to_string(),
        });
        let resolver = ProviderConfigResolver::from_config(&config);

        assert_eq!(resolver.resolve_api_key("testprovider"), Some("config-key".to_string()));
    }

    #[test]
    fn resolve_base_url_from_env() {
        let config = Config::default();
        let mut resolver = ProviderConfigResolver::from_config(&config);
        resolver.env.insert("MYPROVIDER_BASE_URL".to_string(), "http://env.local".to_string());

        assert_eq!(resolver.resolve_base_url("myprovider"), Some("http://env.local".to_string()));
    }

    #[test]
    fn resolve_returns_none_when_missing() {
        let config = Config::default();
        let resolver = ProviderConfigResolver::from_config(&config);

        assert_eq!(resolver.resolve_api_key("nonexistent"), None);
        assert_eq!(resolver.resolve_base_url("nonexistent"), None);
    }
}

use crate::labels::{thought_with_time, tool_running, tool_done};
use crate::model::{AppState, ChatMessage, Role};
use super::{content_has_tool_markers, now, strip_tool_markers};

impl AppState {
    pub(crate) fn set_thinking(&mut self, id: String) {
        self.streaming = true;
        self.current_request_id = Some(id);
        self.thinking_started_at = Some(std::time::Instant::now());
        self.turn_active = true;
        self.current_action = Some("Thinking".to_string());
        self.turn_started_at.get_or_insert_with(std::time::Instant::now);
        self.messages_changed();
    }

    pub(crate) fn add_thought(&mut self, id: String) {
        let duration = self.thinking_elapsed_secs().unwrap_or(0.0);
        self.current_action = None;
        self.thinking_started_at = None;
        let mut insert_idx = self.messages.len();
        let thought_content = if let Some(idx) = self.messages.iter().position(|m| m.role == Role::Assistant && m.id == id) {
            let assistant = &self.messages[idx];
            let has_tools = content_has_tool_markers(&assistant.content);
            let stripped = strip_tool_markers(&assistant.content);
            if has_tools && !stripped.trim().is_empty() {
                self.messages.remove(idx);
                insert_idx = idx;
                format!("{}\n{}", thought_with_time(duration), stripped)
            } else {
                insert_idx = idx;
                thought_with_time(duration)
            }
        } else {
            thought_with_time(duration)
        };
        let thought_id = format!("{}#thought.{}", id, self.thought_seq);
        self.thought_seq += 1;
        let thought = ChatMessage {
            role: Role::Thought,
            content: thought_content,
            timestamp: now(),
            id: thought_id,
        };
        self.messages.insert(insert_idx, thought);
        self.messages_changed();
    }

    pub(crate) fn start_tool(&mut self, id: String, name: String) {
        self.current_request_id = Some(id.clone());
        self.current_tool_name = Some(name.clone());
        self.tool_started_at = Some(std::time::Instant::now());
        self.intermediate_step_count += 1;
        self.current_action = Some(format!("Running {}", name));
        let tool_id = format!("tool.{}.{}", id, self.intermediate_step_count);
        self.messages.push(ChatMessage {
            role: Role::Tool,
            content: tool_running(&name),
            timestamp: now(),
            id: tool_id,
        });
        self.messages_changed();
    }

    pub(crate) fn end_tool(&mut self, duration_secs: f64, output: String) {
        self.current_action = None;
        self.tool_started_at = None;
        if let Some(name) = self.current_tool_name.take() {
            if let Some(idx) = self.messages.iter().rposition(|m| {
                m.role == Role::Tool && m.content.contains("⠋ Running ")
            }) {
                if let Some(last) = self.messages.get_mut(idx) {
                    last.content = if output.trim().is_empty() {
                        tool_done(&name, duration_secs)
                    } else {
                        format!("{}\n{}", tool_done(&name, duration_secs), output)
                    };
                    last.timestamp = now();
                }
            }
        }
        self.messages_changed();
    }

    pub(crate) fn append_response(&mut self, id: String, content: String) {
        // O(1) lookup using cached last_assistant_index
        if let Some(idx) = self.last_assistant_index {
            if let Some(msg) = self.messages.get_mut(idx) {
                if msg.role == Role::Assistant && msg.id == id {
                    if !content.is_empty() {
                        msg.content.push_str(&content);
                    }
                    msg.timestamp = now();
                    self.messages_changed();
                    return;
                }
            }
        }
        // Fallback: search for existing message
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::Assistant && m.id == id) {
            if let Some(msg) = self.messages.get_mut(idx) {
                if !content.is_empty() {
                    msg.content.push_str(&content);
                }
                msg.timestamp = now();
                self.last_assistant_index = Some(idx);
                self.messages_changed();
                return;
            }
        }
        // New message
        if !content.is_empty() {
            let idx = self.messages.len();
            self.messages.push(ChatMessage {
                role: Role::Assistant,
                content,
                timestamp: now(),
                id: id.clone(),
            });
            self.current_request_id = Some(id);
            self.last_assistant_index = Some(idx);
            self.messages_changed();
        }
    }

    pub(crate) fn complete_turn(&mut self, id: String, duration_secs: f64) {
        let content = format!("Turn completed in {:.1}s", duration_secs);
        let ts = now();
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete && m.id == id) {
            self.messages[idx].content = content;
            self.messages[idx].timestamp = ts;
        } else {
            self.messages.push(ChatMessage {
                role: Role::TurnComplete,
                content,
                timestamp: ts,
                id,
            });
        }
        self.messages_changed();
        self.turn_started_at = None;
    }

    pub(crate) fn finish_turn(&mut self, id: String) {
        self.strip_tools_from_assistant();
        self.remove_empty_assistant();
        self.clear_turn_state(&id);
        self.deliver_queued();
        self.maybe_end_streaming();
        self.reorder_agent_after_tools();
        self.move_turn_complete_to_end();
        self.messages_changed();
    }

    fn strip_tools_from_assistant(&mut self) {
        for msg in self.messages.iter_mut() {
            if msg.role == Role::Assistant {
                msg.content = strip_tool_markers(&msg.content);
            }
        }
    }

    fn remove_empty_assistant(&mut self) {
        self.messages.retain(|msg| {
            !(msg.role == Role::Assistant && msg.content.trim().is_empty())
        });
    }

    fn clear_turn_state(&mut self, id: &str) {
        if self.current_request_id.as_deref() == Some(id) {
            self.current_request_id = None;
        }
        self.current_tool_name = None;
        self.current_action = None;
        self.intermediate_step_count = 0;
        self.thought_seq = 0;
        self.turn_active = false;
        self.turn_started_at = None;
        self.inflight = self.inflight.saturating_sub(1);
    }

    fn maybe_end_streaming(&mut self) {
        if self.inflight == 0 && self.request_queue.is_empty() {
            self.streaming = false;
            if self.current_request_id.is_none() {
                self.thinking_started_at = None;
            }
        }
    }

    fn reorder_agent_after_tools(&mut self) {
        let last_assistant = self.messages.iter().rposition(|m| m.role == Role::Assistant);
        let last_tool = self.messages.iter().rposition(|m| m.role == Role::Tool);
        if let (Some(a_idx), Some(t_idx)) = (last_assistant, last_tool) {
            if a_idx < t_idx {
                let mut agent = self.messages.remove(a_idx);
                agent.timestamp = now();
                self.messages.insert(t_idx, agent);
                // Update cached index if it was affected
                if self.last_assistant_index == Some(a_idx) {
                    self.last_assistant_index = Some(t_idx);
                }
            }
        }
    }

    fn move_turn_complete_to_end(&mut self) {
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            let mut turn_complete = self.messages.remove(idx);
            turn_complete.timestamp = now();
            self.messages.push(turn_complete);
            // Update cached index if it was affected
            if let Some(last_idx) = self.last_assistant_index {
                if last_idx >= idx {
                    self.last_assistant_index = Some(last_idx.saturating_sub(1));
                }
            }
        }
    }

    pub(crate) fn add_error(&mut self, id: String, message: String) {
        self.streaming = false;
        let mut error = ChatMessage {
            role: Role::Assistant,
            content: format!("Error: {}", message),
            timestamp: now(),
            id: format!("error.{}", id),
        };
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            error.timestamp = self.messages[idx].timestamp;
            self.messages.insert(idx, error);
        } else {
            self.messages.push(error);
        }
        self.messages_changed();
    }
}

# Dequeue (Alt+Up)

**Status**: done
**Milestone**: R2
**Category**: Input & Commands

## Description

Pop the last queued message back into the input field. Lets users edit or resubmit accidentally queued messages.

## Architecture

```rust
// Command factory
fn cmd_dequeue(_args: &str) -> Option<Event> {
    Some(Event::Dequeue)
}

// Update handler
fn update_dequeue(state: &mut AppState) {
    if let Some((content, _id)) = state.message_queue.last() {
        state.input_text = content.clone();
        state.input_cursor = state.input_text.len();
        state.message_queue.pop();
    } else {
        state.flash_input_border();
    }
}
```

### Keybinding

```json
{
  "app.message.dequeue": "alt+up"
}
```

## Acceptance Criteria

- [ ] `Alt+Up` pops last queued message into input
- [ ] Message removed from queue (not just copied)
- [ ] Cursor positioned at end
- [ ] Non-empty input is replaced
- [ ] Empty queue flashes input border
- [ ] Works for steering and follow-up queues

