//! View — renders Snapshot to terminal via ratatui
//!
//! Architecture: the event loop builds immutable Snapshots;
//! the render actor draws them. No state mutations, no blocking
//! I/O, no caching — pure functions from Snapshot to Frame.
//!
//! DESIGN SYSTEM RULE: all colors, glyphs, and styles come from
//! crate::theme only. No literals, no hardcoded values.

use ratatui::{
    layout::{Constraint, Direction, Layout, Rect},
    style::Color,
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Scrollbar, ScrollbarOrientation, ScrollbarState, Wrap},
    Frame,
};

fn vstack(area: Rect, heights: &[Constraint]) -> Vec<Rect> {
    Layout::default().direction(Direction::Vertical).constraints(heights).split(area).to_vec()
}

fn hstack(area: Rect, widths: &[Constraint]) -> Vec<Rect> {
    Layout::default().direction(Direction::Horizontal).constraints(widths).split(area).to_vec()
}

use runie_core::{Element, Snapshot};

use crate::markdown::{extract_code_blocks, md_to_spans, parse_inline_markdown_with_color, CodeBlock};
use crate::syntax::highlight_code;
use runie_core::format_timestamp;
use crate::theme::{
    GLYPH_USER, GLYPH_AGENT, GLYPH_INDENT,
    GLYPH_SELECTED, GLYPH_UNSELECTED, PANEL_INPUT,
    SCROLLBAR_TRACK, SCROLLBAR_THUMB,
    code_header_label, thinking_line, tool_running_line, tool_done_header,
    tool_summary_line, turn_complete_line, thought_summary_line,
    style_user, style_agent, style_thought, style_thinking, style_thought_summary,
    style_tool_running, style_tool_header, style_tool_output, style_tool_summary,
    style_turn_complete, style_empty_state, style_timestamp, style_status_idle,
    style_status_active, style_border, style_border_flash,
    style_code_header, style_input_cursor, style_placeholder, style_hint,
    style_popup_selected, style_popup_unselected, style_popup_border,
    color_fg_bright, color_fg, set_current_theme,
};

/// Draw a Snapshot to the terminal. Pure function — no mutable state.
pub fn draw_snapshot(f: &mut Frame, snap: &Snapshot) {
    set_current_theme(&snap.theme_name);
    let c = vstack(f.area(), &[
        Constraint::Min(3),
        Constraint::Length(1),
        Constraint::Length(3),
        Constraint::Length(1),
    ]);
    messages(f, snap, c[0]);
    status(f, snap, c[1]);
    input(f, snap, c[2]);
    hints(f, snap, c[3]);
    at_suggestions(f, snap);
    command_palette(f, snap);
}

/// Legacy entry point for code that still builds AppState directly.
pub fn view(f: &mut Frame, state: &mut runie_core::AppState) {
    state.ensure_fresh();
    let snap = state.snapshot();
    draw_snapshot(f, &snap);
}

fn status(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let tokens: usize = snap.elements.iter().map(estimate_element_tokens).sum();
    let left_text = build_status_text(snap);
    let queue_part = if snap.queue_count > 0 {
        format!(" · {} queued", snap.queue_count)
    } else {
        String::new()
    };
    let right_text = format!("{} tok{}", tokens, queue_part);

    let h = hstack(area, &[
        Constraint::Min(0),
        Constraint::Length(right_text.len() as u16),
    ]);

    let status_style = if snap.turn_active {
        style_status_active()
    } else {
        style_status_idle()
    };

    f.render_widget(Paragraph::new(left_text).style(status_style), h[0]);
    f.render_widget(Paragraph::new(right_text).style(style_timestamp()), h[1]);
}

fn build_status_text(snap: &Snapshot) -> String {
    let mut parts = Vec::new();
    parts.push(format!("{}/{}", snap.provider, snap.model));
    if snap.turn_active {
        if let Some(elapsed) = snap.turn_elapsed_secs {
            parts.push(runie_core::labels::action_text(
                snap.spinner_frame, "Working", elapsed,
            ));
        } else {
            parts.push(format!("{} Working...", snap.spinner_frame));
        }
    }
    parts.join(" · ")
}

fn messages(f: &mut Frame, snap: &Snapshot, area: Rect) {
    if snap.elements.is_empty() {
        render_empty_state(f, area);
        return;
    }
    render_message_content(f, snap, area);
}

fn render_empty_state(f: &mut Frame, area: Rect) {
    let hint = Line::from("Type a message to start...").style(style_empty_state());
    f.render_widget(Paragraph::new(hint), area);
}

fn render_message_content(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let height = area.height as usize;
    let total_lines = snap.total_lines;
    if height == 0 || total_lines == 0 {
        return;
    }

    let show_bar = total_lines > height;
    let content_width = if show_bar {
        area.width.saturating_sub(1)
    } else {
        area.width
    };

    let h = hstack(area, &[Constraint::Length(content_width), Constraint::Min(0)]);
    let lines = build_lines(snap);
    let offset = snap.scroll_offset(height);
    f.render_widget(
        Paragraph::new(lines)
            .scroll((offset, 0))
            .wrap(Wrap { trim: false }),
        h[0],
    );

    if show_bar {
        render_scrollbar(f, area, total_lines, offset, height);
    }
}

fn build_lines(snap: &Snapshot) -> Vec<Line<'_>> {
    let mut lines = Vec::with_capacity(snap.total_lines);
    for elem in &snap.elements {
        lines.extend(to_lines(elem, snap.spinner_frame));
    }
    lines
}

fn render_scrollbar(f: &mut Frame, area: Rect, total: usize, offset: u16, height: usize) {
    let scrollbar = Scrollbar::default()
        .orientation(ScrollbarOrientation::VerticalRight)
        .begin_symbol(None)
        .end_symbol(None)
        .track_symbol(Some(SCROLLBAR_TRACK))
        .thumb_symbol(SCROLLBAR_THUMB);

    let mut state = ScrollbarState::new(total)
        .position(offset as usize)
        .viewport_content_length(height);
    f.render_stateful_widget(scrollbar, area, &mut state);
}

fn to_lines<'a>(elem: &'a Element, _spinner_frame: char) -> Vec<Line<'a>> {
    use runie_core::Element::*;
    match elem {
        Spacer { .. } => vec![Line::from("")],
        UserMessage { content, timestamp } => render_message(content, *timestamp, GLYPH_USER, color_fg_bright()),
        AgentMessage { content, timestamp } => render_agent_message(content, *timestamp),
        Thinking { started, .. } => vec![Line::from(
            thinking_line(started.elapsed().as_secs_f64())
        ).style(style_thinking())],
        ThoughtSummary { content, .. } => vec![Line::from(
            thought_summary_line(content.lines().next().unwrap_or(content))
        ).style(style_thought_summary())],
        ThoughtMarker { content, .. } => render_thought_marker(content),
        ToolRunning { name, started, .. } => vec![Line::from(
            tool_running_line(name, started.elapsed().as_secs_f64())
        ).style(style_tool_running())],
        ToolDone { name, duration_secs, output, .. } => render_tool_done(name, *duration_secs, output),
        ToolSummary { name, duration_secs, .. } => vec![Line::from(
            tool_summary_line(name, *duration_secs)
        ).style(style_tool_summary())],
        TurnComplete { duration_secs, .. } => vec![Line::from(
            turn_complete_line(*duration_secs)
        ).style(style_turn_complete())],
    }
}

fn render_message(content: &str, timestamp: f64, first_prefix: &'static str, base_color: Color) -> Vec<Line<'static>> {
    let mut lines = Vec::new();
    let ts_str = format_timestamp(timestamp);
    let base_style = if base_color == color_fg_bright() { style_user() } else { style_agent() };
    for (i, line) in content.lines().enumerate() {
        let prefix = if i == 0 { first_prefix } else { GLYPH_INDENT };
        let ts = format!(" {:>5}", ts_str);
        let mut spans = vec![Span::styled(prefix, base_style)];
        spans.extend(md_to_spans(&parse_inline_markdown_with_color(line, base_color)));
        spans.push(Span::styled(ts, style_timestamp()));
        lines.push(Line::from(spans));
    }
    if lines.is_empty() {
        lines.push(Line::from(format!("{}{:>5}", first_prefix, ts_str)).style(base_style));
    }
    lines
}

fn render_list_item(item: &str, ordered: bool, idx: usize, is_first: bool, ts_str: &str) -> Line<'static> {
    let bullet = if ordered { format!("{}.", idx + 1) } else { "•".to_string() };
    let first_line_prefix = if is_first { format!("{} {}", GLYPH_AGENT, bullet) } else { format!("{} {}", GLYPH_INDENT, bullet) };
    let rest_prefix = format!("{}   ", GLYPH_INDENT);
    let first_ts = format!(" {:>5}", ts_str);
    let rest_ts = "      ".to_string();
    let lines: Vec<&str> = item.lines().collect();
    let mut text = String::new();
    for (j, line) in lines.iter().enumerate() {
        let prefix = if j == 0 { &first_line_prefix } else { &rest_prefix };
        let ts = if j == 0 { &first_ts } else { &rest_ts };
        text.push_str(prefix);
        text.push_str(line);
        text.push_str(ts);
        if j + 1 < lines.len() {
            text.push('\n');
        }
    }
    Line::from(text).style(style_agent())
}

fn render_code_block_lines(content: &str, lang: &str, ts_str: &str) -> Vec<Line<'static>> {
    let highlighted = highlight_code(content, lang);
    highlighted
        .into_iter()
        .map(|tokens| {
            let mut spans = vec![Span::raw(GLYPH_INDENT.to_string())];
            for token in tokens {
                spans.push(Span::styled(token.content, token.style));
            }
            spans.push(Span::raw(format!(" {:>5}", ts_str)));
            Line::from(spans)
        })
        .collect()
}

fn render_blockquote_lines(text: &str) -> Vec<Line<'static>> {
    text.lines()
        .map(|line| Line::from(format!("{}│ {}", GLYPH_INDENT, line)).style(style_agent()))
        .collect()
}

fn render_agent_message(content: &str, timestamp: f64) -> Vec<Line<'static>> {
    let blocks = extract_code_blocks(content);
    let mut lines = Vec::new();
    let mut is_first = true;
    let ts_str = format_timestamp(timestamp);

    for block in blocks {
        match block {
            CodeBlock::Text(text) => {
                for line in text.lines() {
                    lines.push(render_msg_line(line, timestamp, is_first));
                    is_first = false;
                }
            }
            CodeBlock::Code { lang, content } => {
                lines.push(render_code_header(&lang, is_first));
                is_first = false;
                lines.extend(render_code_block_lines(&content, &lang, &ts_str));
            }
            CodeBlock::List { ordered, items } => {
                for (i, item) in items.iter().enumerate() {
                    let rendered = render_list_item(item, ordered, i, is_first, &ts_str);
                    lines.push(rendered);
                    is_first = false;
                }
            }
            CodeBlock::Blockquote(text) => {
                lines.extend(render_blockquote_lines(&text));
                is_first = false;
            }
        }
    }
    if lines.is_empty() {
        lines.push(Line::from(format!("{}{:>5}", GLYPH_AGENT, ts_str)).style(style_agent()));
    }
    lines
}

fn render_code_header(lang: &str, is_first: bool) -> Line<'static> {
    let prefix = if is_first { GLYPH_AGENT } else { GLYPH_INDENT };
    Line::from(code_header_label(prefix, lang)).style(style_code_header())
}

fn render_msg_line(line: &str, timestamp: f64, is_first: bool) -> Line<'static> {
    let prefix = if is_first { GLYPH_AGENT } else { GLYPH_INDENT };
    let ts = format!(" {:>5}", format_timestamp(timestamp));
    let mut spans = vec![Span::styled(prefix.to_string(), style_agent())];
    spans.extend(md_to_spans(&parse_inline_markdown_with_color(line, color_fg())));
    spans.push(Span::styled(ts, style_timestamp()));
    Line::from(spans)
}

fn render_thought_marker(content: &str) -> Vec<Line<'static>> {
    content.lines()
        .map(|line| Line::from(line.to_string()).style(style_thought()))
        .collect()
}

fn render_tool_done(name: &str, duration_secs: f64, output: &str) -> Vec<Line<'static>> {
    let mut lines = vec![Line::from(tool_done_header(name, duration_secs))
        .style(style_tool_header())];
    if !output.is_empty() {
        // Check if output is a diff and render with highlighting
        if crate::diff::is_diff_output(output) {
            lines.extend(crate::diff::render_diff_text(output));
        } else {
            for line in output.lines() {
                lines.push(Line::from(line.to_string()).style(style_tool_output()));
            }
        }
    }
    lines
}

fn input(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let border_style = if snap.input_flash > 0 {
        style_border_flash()
    } else {
        style_border()
    };
    let block = Block::default()
        .borders(Borders::ALL)
        .title(PANEL_INPUT)
        .border_style(border_style);
    let inner = block.inner(area);

    let spans = build_input_spans(snap);
    f.render_widget(Paragraph::new(Line::from(spans)).block(block), area);

    let cursor_x = inner.x + (GLYPH_USER.len() + snap.cursor_pos.min(snap.input.len())) as u16;
    f.set_cursor_position((cursor_x, inner.y));
}

fn build_input_spans(snap: &Snapshot) -> Vec<Span<'_>> {
    if snap.input.is_empty() && !snap.placeholder.is_empty() {
        return vec![
            Span::styled(GLYPH_USER, style_user()),
            Span::styled(snap.placeholder.clone(), style_placeholder()),
        ];
    }
    let cursor_pos = snap.cursor_pos.min(snap.input.len());
    let before = &snap.input[..cursor_pos];
    let (at_cursor, after) = if cursor_pos < snap.input.len() {
        let c = snap.input[cursor_pos..].chars().next().unwrap();
        let char_len = c.len_utf8();
        (c, &snap.input[cursor_pos + char_len..])
    } else {
        (' ', "")
    };
    vec![
        Span::styled(GLYPH_USER, style_user()),
        Span::styled(before, style_user()),
        Span::styled(at_cursor.to_string(), style_input_cursor()),
        Span::styled(after, style_user()),
    ]
}

fn hints(f: &mut Frame, _snap: &Snapshot, area: Rect) {
    let hints_text = "Ctrl+Shift+E=expand/collapse | Alt+Enter=follow-up | Esc=clear | Ctrl+C=quit";
    f.render_widget(Paragraph::new(hints_text).style(style_hint()), area);
}

fn at_suggestions(f: &mut Frame, snap: &Snapshot) {
    let suggestions = match &snap.at_suggestions {
        Some(s) if !s.is_empty() => s,
        _ => return,
    };
    let selected = snap.at_selected.unwrap_or(0).min(suggestions.len().saturating_sub(1));
    let area = f.area();
    let display_count = suggestions.len().min(8) as u16;
    let max_height = display_count + 4;
    let popup_area = Rect {
        x: area.x + 1,
        y: area.y + area.height.saturating_sub(4 + max_height),
        width: area.width.saturating_sub(2).max(20),
        height: max_height,
    };
    let mut lines: Vec<Line> = suggestions
        .iter()
        .take(8)
        .enumerate()
        .map(|(i, s)| {
            let prefix = if i == selected { GLYPH_SELECTED } else { GLYPH_UNSELECTED };
            let style = if i == selected { style_popup_selected() } else { style_popup_unselected() };
            Line::from(format!("{}{}", prefix, s)).style(style)
        })
        .collect();
    lines.push(Line::from(""));
    lines.push(
        Line::from("Tab=cycle Enter=insert Esc=close").style(style_hint()),
    );
    let block = Block::default()
        .borders(Borders::ALL)
        .title(format!(" @ files ({}) ", suggestions.len()))
        .border_style(style_popup_border());
    f.render_widget(Paragraph::new(lines).block(block), popup_area);
}

fn command_palette(f: &mut Frame, snap: &Snapshot) {
    let (filter, selected) = match &snap.dialog {
        Some(runie_core::commands::DialogState::CommandPalette { filter, selected }) => (filter.clone(), *selected),
        _ => return,
    };
    let popup_area = palette_popup_rect(f.area());
    let lines = build_palette_lines(snap, &filter, selected);
    let block = Block::default()
        .borders(Borders::ALL)
        .title(" Commands ")
        .border_style(style_popup_border());
    f.render_widget(Paragraph::new(lines).block(block), popup_area);
}

fn palette_popup_rect(area: Rect) -> Rect {
    let popup_width = 60u16.min(area.width.saturating_sub(4)).max(20);
    let popup_height = 18u16.min(area.height.saturating_sub(4)).max(6);
    Rect {
        x: area.x + (area.width.saturating_sub(popup_width)) / 2,
        y: area.y + (area.height.saturating_sub(popup_height)) / 2,
        width: popup_width,
        height: popup_height,
    }
}

fn build_palette_lines<'a>(snap: &'a Snapshot, filter: &str, selected: usize) -> Vec<Line<'a>> {
    let mut lines: Vec<Line> = Vec::new();
    lines.push(Line::from(format!("> {}", filter)).style(style_user()));
    lines.push(Line::from(""));

    if snap.palette_items.is_empty() {
        lines.push(Line::from("No commands found").style(style_hint()));
        return lines;
    }

    let mut last_category = String::new();
    for (i, (name, desc, category)) in snap.palette_items.iter().enumerate() {
        if category != &last_category {
            if !last_category.is_empty() {
                lines.push(Line::from(""));
            }
            lines.push(Line::from(format!("  {}", category)).style(style_thinking()));
            last_category = category.clone();
        }
        let style = if i == selected { style_popup_selected() } else { style_popup_unselected() };
        lines.push(Line::from(format!("    {:12} {}", name, desc)).style(style));
    }
    lines
}

fn estimate_element_tokens(elem: &Element) -> usize {
    use runie_core::Element::*;
    match elem {
        UserMessage { content, .. }
        | AgentMessage { content, .. }
        | ThoughtMarker { content, .. } => content.len() / 4,
        Thinking { .. }
        | ThoughtSummary { .. }
        | ToolSummary { .. }
        | TurnComplete { .. } => 10,
        ToolRunning { .. } => 10,
        ToolDone { output, .. } => output.len() / 4 + 10,
        Spacer { .. } => 0,
    }
}

//! UI Elements - Building blocks for the DSL

#[derive(Debug, Clone)]
pub enum Element {
    Spacer { timestamp: f64 },
    UserMessage { content: String, timestamp: f64 },
    AgentMessage { content: String, timestamp: f64 },
    Thinking { started: std::time::Instant, timestamp: f64 },
    ThoughtMarker { content: String, timestamp: f64 },
    ThoughtSummary { content: String, duration_secs: f64, timestamp: f64 },
    ToolRunning { name: String, started: std::time::Instant, timestamp: f64 },
    ToolDone { name: String, duration_secs: f64, output: String, timestamp: f64 },
    ToolSummary { name: String, duration_secs: f64, timestamp: f64 },
    TurnComplete { duration_secs: f64, timestamp: f64 },
}

/// Builder for attaching a timestamp to an Element.
pub struct ElementBuilder(pub(crate) Element);

impl ElementBuilder {
    pub fn at(self, timestamp: f64) -> Element {
        let mut e = self.0;
        match &mut e {
            Element::Spacer { timestamp: ts } => *ts = timestamp,
            Element::UserMessage { timestamp: ts, .. } => *ts = timestamp,
            Element::AgentMessage { timestamp: ts, .. } => *ts = timestamp,
            Element::Thinking { timestamp: ts, .. } => *ts = timestamp,
            Element::ThoughtMarker { timestamp: ts, .. } => *ts = timestamp,
            Element::ThoughtSummary { timestamp: ts, .. } => *ts = timestamp,
            Element::ToolRunning { timestamp: ts, .. } => *ts = timestamp,
            Element::ToolDone { timestamp: ts, .. } => *ts = timestamp,
            Element::ToolSummary { timestamp: ts, .. } => *ts = timestamp,
            Element::TurnComplete { timestamp: ts, .. } => *ts = timestamp,
        }
        e
    }
}

impl Element {
    pub fn user(content: impl Into<String>) -> ElementBuilder {
        ElementBuilder(Element::UserMessage { content: content.into(), timestamp: 0.0 })
    }
    pub fn agent(content: impl Into<String>) -> ElementBuilder {
        ElementBuilder(Element::AgentMessage { content: content.into(), timestamp: 0.0 })
    }
    pub fn thinking(started: std::time::Instant) -> ElementBuilder {
        ElementBuilder(Element::Thinking { started, timestamp: 0.0 })
    }
    pub fn thought(content: impl Into<String>) -> ElementBuilder {
        ElementBuilder(Element::ThoughtMarker { content: content.into(), timestamp: 0.0 })
    }
    pub fn thought_summary(content: impl Into<String>, duration_secs: f64) -> ElementBuilder {
        ElementBuilder(Element::ThoughtSummary { content: content.into(), duration_secs, timestamp: 0.0 })
    }
    pub fn tool_running(name: impl Into<String>, started: std::time::Instant) -> ElementBuilder {
        ElementBuilder(Element::ToolRunning { name: name.into(), started, timestamp: 0.0 })
    }
    pub fn tool_done(name: impl Into<String>, duration_secs: f64, output: impl Into<String>) -> ElementBuilder {
        ElementBuilder(Element::ToolDone { name: name.into(), duration_secs, output: output.into(), timestamp: 0.0 })
    }
    pub fn tool_summary(name: impl Into<String>, duration_secs: f64) -> ElementBuilder {
        ElementBuilder(Element::ToolSummary { name: name.into(), duration_secs, timestamp: 0.0 })
    }
    pub fn turn_complete(duration_secs: f64) -> ElementBuilder {
        ElementBuilder(Element::TurnComplete { duration_secs, timestamp: 0.0 })
    }
    pub fn spacer() -> ElementBuilder {
        ElementBuilder(Element::Spacer { timestamp: 0.0 })
    }


    pub fn is_thought(&self) -> bool {
        matches!(self, Element::ThoughtMarker { .. })
    }

    /// Sort key for ordering elements in the feed.
    pub fn timestamp(&self) -> f64 {
        match self {
            Element::Spacer { timestamp } => *timestamp,
            Element::UserMessage { timestamp, .. } => *timestamp,
            Element::AgentMessage { timestamp, .. } => *timestamp,
            Element::Thinking { timestamp, .. } => *timestamp,
            Element::ThoughtMarker { timestamp, .. } => *timestamp,
            Element::ThoughtSummary { timestamp, .. } => *timestamp,
            Element::ToolRunning { timestamp, .. } => *timestamp,
            Element::ToolDone { timestamp, .. } => *timestamp,
            Element::ToolSummary { timestamp, .. } => *timestamp,
            Element::TurnComplete { timestamp, .. } => *timestamp,
        }
    }

    /// Number of terminal lines this element renders to.
    /// Must stay in sync with `to_lines()` in `runie-tui/src/ui.rs`.
    pub fn line_count(&self) -> usize {
        match self {
            Element::Spacer { .. } => 1,
            Element::UserMessage { content, .. } => content.lines().count().max(1),
            Element::AgentMessage { content, .. } => content.lines().count().max(1),
            Element::Thinking { .. } => 1,
            Element::ThoughtMarker { content, .. } => content.lines().count().max(1),
            Element::ThoughtSummary { .. } => 1,
            Element::ToolRunning { .. } => 1,
            Element::ToolDone { output, .. } => {
                if output.is_empty() { 1 } else { 1 + output.lines().count() }
            }
            Element::ToolSummary { .. } => 1,
            Element::TurnComplete { .. } => 1,
        }
    }
}

#[derive(Debug, Clone, Default)]
pub struct Feed {
    pub elements: Vec<Element>,
}

impl Feed {
    pub fn new() -> Self {
        Self { elements: vec![] }
    }

    pub fn push(mut self, element: Element) -> Self {
        self.elements.push(element);
        self
    }

    pub fn extend(mut self, elements: Vec<Element>) -> Self {
        self.elements.extend(elements);
        self
    }

    pub fn len(&self) -> usize {
        self.elements.len()
    }

    pub fn is_empty(&self) -> bool {
        self.elements.is_empty()
    }
}

use crate::model::{AppState, ChatMessage, Role};
use crate::ui::elements::{Element, Feed};

pub struct LazyCache;

impl LazyCache {
    pub fn rebuild(state: &AppState) -> Vec<Element> {
        Self::build(state).elements
    }

    pub fn feed(state: &AppState) -> Feed {
        Self::build(state)
    }

    fn build(state: &AppState) -> Feed {
        let mut entries = Self::collect_entries(state);
        entries.sort_by(|a, b| {
            a.timestamp().partial_cmp(&b.timestamp())
                .unwrap_or(std::cmp::Ordering::Equal)
        });

        let mut feed = Feed::new();
        for elem in entries {
            let ts = elem.timestamp();
            feed.elements.push(elem);
            feed.elements.push(Element::spacer().at(ts));
        }
        feed
    }

    fn collect_entries(state: &AppState) -> Vec<Element> {
        let mut entries: Vec<Element> = Vec::new();

        for msg in state.messages.iter() {
            if Self::should_skip_msg(msg, state) {
                continue;
            }
            entries.push(Self::msg_to_elem(msg, state));
        }

        if let Some(started) = state.thinking_started_at {
            let max_ts = state.messages.iter().map(|m| m.timestamp).fold(0.0, f64::max);
            let turn_ts = state.messages.iter()
                .find(|m| m.role == Role::TurnComplete)
                .map(|m| m.timestamp);
            let turn_complete_for_current = state.current_request_id.as_ref().and_then(|id| {
                state.messages.iter()
                    .find(|m| m.role == Role::TurnComplete && m.id == *id)
                    .map(|m| m.timestamp)
            });
            let ts = if let Some(tc_ts) = turn_complete_for_current {
                tc_ts - 1e-6
            } else {
                turn_ts.map(|t| t + 1e-6).unwrap_or(max_ts + 1e-6)
            };
            entries.push(Element::thinking(started).at(ts));
        }

        entries
    }

    fn should_skip_msg(msg: &ChatMessage, state: &AppState) -> bool {
        if msg.role != Role::Assistant {
            return false;
        }
        if crate::update::content_has_tool_markers(&msg.content) {
            return true;
        }
        state.thinking_started_at.is_some()
            && state.current_request_id.as_deref() == Some(&msg.id)
    }

    pub fn visible(cache: &[Element], skip: usize, take: usize) -> &[Element] {
        let start = skip.min(cache.len());
        let end = (start + take).min(cache.len());
        &cache[start..end]
    }

    fn msg_to_elem(msg: &ChatMessage, state: &AppState) -> Element {
        let ts = msg.timestamp;
        match msg.role {
            Role::User => Element::user(msg.content.clone()).at(ts),
            Role::Thought => Self::thought_elem(msg, state, ts),
            Role::Assistant => Element::agent(crate::update::strip_tool_markers(&msg.content)).at(ts),
            Role::Tool => Self::tool_elem(msg, state, ts),
            Role::TurnComplete => Element::turn_complete(Self::parse_dur(&msg.content)).at(ts),
            Role::System => Element::thought(msg.content.clone()).at(ts),
        }
    }

    fn thought_elem(msg: &ChatMessage, state: &AppState, ts: f64) -> Element {
        if state.all_collapsed {
            let first_line = msg.content.lines().next().unwrap_or(&msg.content).to_string();
            Element::thought_summary(first_line, Self::parse_thought_dur(&msg.content)).at(ts)
        } else {
            Element::thought(msg.content.clone()).at(ts)
        }
    }

    fn parse_thought_dur(content: &str) -> f64 {
        content.split_whitespace().last()
            .and_then(|s| s.trim_end_matches('s').parse().ok())
            .unwrap_or(0.0)
    }

    fn tool_elem(msg: &ChatMessage, state: &AppState, ts: f64) -> Element {
        if msg.content.contains("⠋ Running ") {
            let name = msg.content.trim_start_matches("⠋ Running ").trim_end_matches("...");
            return Element::tool_running(name, state.tool_started_at.unwrap_or_else(std::time::Instant::now)).at(ts);
        }
        let (name, dur, output) = Self::parse_tool_content(&msg.content);
        if state.all_collapsed {
            Element::tool_summary(name, dur).at(ts)
        } else {
            Element::tool_done(name, dur, output).at(ts)
        }
    }

    fn parse_tool_content(content: &str) -> (String, f64, String) {
        let lines: Vec<&str> = content.lines().collect();
        let header = lines.first().copied().unwrap_or("");
        let output = lines.get(1..).map(|rest| rest.join("\n")).unwrap_or_default();
        let parts: Vec<&str> = header.split_whitespace().collect();
        let name = parts.get(1).unwrap_or(&"").to_string();
        let dur = parts.last().and_then(|s| s.trim_end_matches('s').parse().ok()).unwrap_or(0.0);
        (name, dur, output)
    }

    fn parse_dur(content: &str) -> f64 {
        content.split_whitespace().last()
            .and_then(|s| s.trim_end_matches('s').parse().ok())
            .unwrap_or(0.0)
    }
}

