fn tool_running_builder() {
    let started = std::time::Instant::now();
    let e = Element::tool_running("ls", started).at(5.0);
    assert!(matches!(e, Element::ToolRunning { name, timestamp, .. }
        if name == "ls" && timestamp == 5.0));
}

