fn tool_done_builder() {
    let e = Element::tool_done("ls", 0.5, "file1").at(6.0);
    assert!(matches!(e, Element::ToolDone { name, duration_secs, output, timestamp }
        if name == "ls" && duration_secs == 0.5 && output == "file1" && timestamp == 6.0));
}

